import { useEffect, useState } from "react";

const SIZE = 10;

const EMPTY = 0;
const SNAKE = 1;
const FOOD = 2;

function newSnake() {
  return [[5, 5]];
}

function randomFood(snake) {
  while (true) {
    const row = Math.floor(Math.random() * SIZE);
    const col = Math.floor(Math.random() * SIZE);

    const occupied = snake.some(
      ([r, c]) => r === row && c === col
    );

    if (!occupied) {
      return [row, col];
    }
  }
}

function moveSnake(snake, direction, food) {
  const [row, col] = snake[0];

  const head = [
    row + direction[0],
    col + direction[1],
  ];

  if (
    head[0] < 0 ||
    head[0] >= SIZE ||
    head[1] < 0 ||
    head[1] >= SIZE
  ) {
    return {
      snake,
      food,
    };
  }

  const nextSnake = [
    head,
    ...snake,
  ];

  if (
    head[0] === food[0] &&
    head[1] === food[1]
  ) {
    return {
      snake: nextSnake,
      food: randomFood(nextSnake),
    };
  }

  nextSnake.pop();

  return {
    snake: nextSnake,
    food,
  };
}

function createBoard(snake, food) {
  const board = Array.from(
    { length: SIZE },
    () => Array(SIZE).fill(EMPTY)
  );

  for (const [r, c] of snake) {
    board[r][c] = SNAKE;
  }

  board[food[0]][food[1]] = FOOD;

  return board;
}

export default function Snake() {
  const [snake, setSnake] = useState([[5, 5]]);
  const [food, setFood] = useState([2, 2]);
  const [direction, setDirection] = useState([0, 1]);

  useEffect(() => {
    function keyDown(e) {
      if (e.key === "ArrowUp") {
        setDirection([-1, 0]);
      }

      if (e.key === "ArrowDown") {
        setDirection([1, 0]);
      }

      if (e.key === "ArrowLeft") {
        setDirection([0, -1]);
      }

      if (e.key === "ArrowRight") {
        setDirection([0, 1]);
      }
    }

    window.addEventListener("keydown", keyDown);

    return () => {
      window.removeEventListener("keydown", keyDown);
    };
  }, []);

  useEffect(() => {
    const timer = setInterval(() => {
      const result = moveSnake(
        snake,
        direction,
        food
      );

      setSnake(result.snake);
      setFood(result.food);
    }, 300);

    return () => clearInterval(timer);
  }, [snake, direction, food]);

  const board = createBoard(snake, food);

  return (
    <main>
      <h1>🐍 Snake</h1>

      <table>
        <tbody>
          {board.map((row, r) => (
            <tr key={r}>
              {row.map((cell, c) => (
                <td
                  key={c}
                  style={{
                    width: "2rem",
                    height: "2rem",
                    border: "1px solid",
                    padding: 0,
                    background:
                      cell === SNAKE
                        ? "green"
                        : cell === FOOD
                        ? "red"
                        : "white",
                  }}
                />
              ))}
            </tr>
          ))}
        </tbody>
      </table>
    </main>
  );
}
